import styles from './Problem.module.css';
import { CircleCheck } from 'lucide-react';

const Problem = () => {
    const features = [
        'ادارة تسجيل المدربين',
        'متابعة المدفوعات',
        'الوصول لطلاب جدد',
        'ادارة تسجيل الطلاب',
        'تنظيم الكورسات',
    ];

    return (
        <section className={styles.problem}>
            <div className={`${styles.container} container`}>
                <div className={styles.imageSide}>
                    <div className={styles.imageWrapper}>
                        <div className={styles.placeholderImg}></div>
                    </div>
                </div>

                <div className={styles.content}>
                    <h2 className={styles.title}>هل تواجه صعوبة في ادارة اكاديميتك ؟</h2>
                    <ul className={styles.list}>
                        {features.map((feature, index) => (
                            <li key={index} className={styles.item}>
                                <span>{feature}</span>
                                <CircleCheck className={styles.icon} size={24} />
                            </li>
                        ))}
                    </ul>
                </div>
            </div>

            <div className={styles.textBlock}>
                <p>منصتنا بتوفر لك كل الأدوات اللي تحتاجها <br /> لإدارة أكاديميتك باحتراف في مكان واحد.</p>
            </div>
        </section>
    );
};

export default Problem;
