import Image from 'next/image';
import img1 from '@/assets/img1.jpg';
import img2 from '@/assets/img2.jpg';

const Hero = () => {
    return (
        <section className="bg-white py-24 overflow-hidden relative">
            <div className="container mx-auto px-4 flex flex-col lg:flex-row items-center justify-between gap-32">
                {/* Left Image Side */}
                <div className="flex-1 hidden lg:flex justify-center relative px-8 translate-y-10">
                    <div className="w-[280px] h-[480px] rounded-[140px] overflow-hidden relative bg-[#f0f0f0] border-8 border-[#fbbf24]">
                        <Image src={img1} alt="Student learning" className="w-full h-full object-cover" priority />
                        <div className="absolute left-[-50px] bottom-[10%] flex flex-col gap-3 z-[5]">
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[30px] -rotate-[30deg]"></span>
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[45px] -rotate-[15deg] -ml-1.5"></span>
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[35px] rotate-0 -ml-4"></span>
                        </div>
                    </div>
                </div>

                <div className="flex-[1.2] text-center z-10">
                    <h1 className="text-6xl font-black leading-tight mb-8 text-[#2563eb]">
                        ابدأ إدارة أكاديميتك <br />
                        <span className="text-[#fbbf24]">بسهولة</span>
                    </h1>
                    <p className="text-xl text-[#6b7280] mb-12 max-w-lg mx-auto">
                        كل الأدوات اللي تحتاجها لإدارة الخدمات، العملاء، والحجوزات في مكان واحد. اختر باقتك وابدأ خلال دقائق.
                    </p>
                    <button className="px-14 py-5 text-2xl font-bold bg-[#2563eb] text-white rounded-2xl cursor-pointer shadow-[0_10px_15px_-3px_rgba(37,99,235,0.3)] hover:-translate-y-1 transition-all">
                        أختر باقتك الآن
                    </button>
                </div>

                {/* Right Image Side */}
                <div className="flex-1 hidden lg:flex justify-center relative px-8 -translate-y-10">
                    <div className="w-[280px] h-[480px] rounded-[140px] overflow-hidden relative bg-[#f0f0f0] border-8 border-[#2563eb]">
                        <Image src={img2} alt="Instructor working" className="w-full h-full object-cover" priority />
                        <div className="absolute right-[-50px] top-[5%] flex flex-col gap-3 z-[5]">
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[35px] rotate-[45deg]"></span>
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[50px] rotate-[30deg] -mr-1.5"></span>
                            <span className="h-[2px] bg-[#2563eb] rounded-[4px] shadow-[0_0_10px_rgba(37,99,235,0.2)] w-[40px] rotate-[15deg] -mr-4"></span>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Hero;
