import styles from './Benefits.module.css';
import { Newspaper, LayoutDashboard, Share2 } from 'lucide-react';

const Benefits = () => {
    const steps = [
        {
            number: '01',
            title: 'لوحة تحكم متكاملة لإدارة الأكاديمية',
            desc: 'متابعة يومية لكل تفاصيل أكاديميتك بسهولة',
            icon: <LayoutDashboard size={24} />
        },
        {
            number: '02',
            title: 'تقارير وإيصالات فورية',
            desc: 'إصدار وتنظيم الفواتير من أي مكان وفي أي وقت',
            icon: <Newspaper size={24} />
        },
        {
            number: '03',
            title: 'إدارة الاشتراكات والمدفوعات',
            desc: 'تحكم عملي في الفواتير ومتابعة الاشتراكات',
            icon: <Share2 size={24} />
        },
    ];

    return (
        <section className={styles.benefits}>
            <div className={`${styles.container} container`}>
                <div className={styles.steps}>
                    {steps.map((step, index) => (
                        <div key={index} className={styles.step}>
                            <div className={styles.number}>{step.number}</div>
                            <div className={styles.iconBox}>
                                {step.icon}
                            </div>
                            <div className={styles.stepContent}>
                                <h3>{step.title}</h3>
                                <p>{step.desc}</p>
                            </div>
                        </div>
                    ))}
                </div>

                <div className={styles.showcase}>
                    <div className={styles.cardMain}>
                        <div className={styles.placeholderImg}></div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Benefits;
