import Link from 'next/link';
import styles from './Nav.module.css';

const Nav = () => {
    return (
        <nav className={styles.nav}>
            <div className={`${styles.container} container`}>
                <div className={styles.logo}>
                    <Link href="/">First</Link>
                </div>

                <ul className={styles.menu}>
                    <li><Link href="/" className={styles.active}>الرئيسية</Link></li>
                    <li><Link href="/about">من نحن</Link></li>
                    <li><Link href="/articles">المقالات</Link></li>
                    <li><Link href="/contact">تواصل معنا</Link></li>
                </ul>

                <div className={styles.actions}>
                    <button className={`${styles.btn} btn btn-outline`}>إنشاء حساب</button>
                    <button className={`${styles.btn} btn btn-primary`}>تسجيل الدخول</button>
                </div>
            </div>
        </nav>
    );
};

export default Nav;
